blocks.body:
{
    "level": "B1–B2",
    "intro": "W tym temacie nauczysz się tworzyć <strong>question tags</strong>, czyli krótkie pytania na końcu zdania służące do potwierdzania informacji i podtrzymywania rozmowy.",
    "rules": [
        {
            "label": "TWIERDZENIE + TAG PRZECZĄCY",
            "color": "emerald",
            "text": "Po zdaniu twierdzącym używamy <strong>tagu przeczącego</strong>:",
            "example": "You like coffee, don't you?"
        },
        {
            "label": "PRZECZENIE + TAG TWIERDZĄCY",
            "color": "blue",
            "text": "Po zdaniu przeczącym używamy <strong>tagu twierdzącego</strong>:",
            "example": "You don't like coffee, do you?"
        },
        {
            "label": "INTONACJA",
            "color": "amber",
            "text": "Intonacja opadająca brzmi jak potwierdzenie, a wznosząca jak prawdziwe pytanie:",
            "example": "It's nice, isn't it? ↘ / ↗"
        }
    ]
}

{
    "title": "1. Co to są question tags?",
    "intro": "Question tag to krótki dodatek na końcu zdania:",
    "items": [
        {
            "label": "Zdanie twierdzące",
            "title": "She is happy, isn't she?",
            "subtitle": "Twierdzenie + tag przeczący"
        },
        {
            "label": "Zdanie przeczące",
            "title": "She isn't happy, is she?",
            "subtitle": "Przeczenie + tag twierdzący"
        },
        {
            "label": "Podstawowa zasada",
            "title": "Zdanie + przeciwna forma w tagu",
            "subtitle": "Tag ma odwrotną biegunowość niż główne zdanie"
        }
    ]
}

{
    "title": "2. Question tags z TO BE",
    "sections": [
        {
            "label": "Present Simple",
            "color": "emerald",
            "description": "Z czasownikiem <strong>to be</strong> powtarzamy odpowiednią formę w tagu.",
            "examples": [
                {
                    "en": "She is happy, isn't she?",
                    "ua": "Ona jest szczęśliwa, prawda?"
                },
                {
                    "en": "You are tired, aren't you?",
                    "ua": "Jesteś zmęczony, prawda?"
                },
                {
                    "en": "He is a doctor, isn't he?",
                    "ua": "On jest lekarzem, prawda?"
                },
                {
                    "en": "They are British, aren't they?",
                    "ua": "Oni są Brytyjczykami, prawda?"
                }
            ]
        },
        {
            "label": "Zdania przeczące",
            "color": "sky",
            "description": "Po zdaniu przeczącym wstawiamy tag twierdzący.",
            "examples": [
                {
                    "en": "She isn't happy, is she?",
                    "ua": "Ona nie jest szczęśliwa, prawda?"
                },
                {
                    "en": "You aren't tired, are you?",
                    "ua": "Nie jesteś zmęczony, prawda?"
                },
                {
                    "en": "He isn't a doctor, is he?",
                    "ua": "On nie jest lekarzem, prawda?"
                },
                {
                    "en": "They aren't British, are they?",
                    "ua": "Oni nie są Brytyjczykami, prawda?"
                }
            ]
        },
        {
            "label": "Past Simple",
            "color": "purple",
            "description": "W czasie przeszłym używamy <strong>was</strong> i <strong>were</strong>.",
            "examples": [
                {
                    "en": "It was great, wasn't it?",
                    "ua": "To było świetne, prawda?"
                },
                {
                    "en": "They were late, weren't they?",
                    "ua": "Spóźnili się, prawda?"
                },
                {
                    "en": "She wasn't there, was she?",
                    "ua": "Nie było jej tam, prawda?"
                }
            ],
            "note": "📌 Zachowujemy tę samą formę czasownika, ale odwracamy biegunowość tagu."
        }
    ]
}

{
    "title": "3. Question tags z DO/DOES/DID",
    "sections": [
        {
            "label": "Present Simple",
            "color": "blue",
            "description": "W Present Simple używamy w tagu <strong>do</strong> albo <strong>does</strong>.",
            "examples": [
                {
                    "en": "You like coffee, don't you?",
                    "ua": "Lubisz kawę, prawda?"
                },
                {
                    "en": "She works here, doesn't she?",
                    "ua": "Ona tu pracuje, prawda?"
                },
                {
                    "en": "They live in London, don't they?",
                    "ua": "Oni mieszkają w Londynie, prawda?"
                },
                {
                    "en": "He knows the answer, doesn't he?",
                    "ua": "On zna odpowiedź, prawda?"
                }
            ]
        },
        {
            "label": "Zdania przeczące",
            "color": "amber",
            "description": "Po zdaniu przeczącym pojawia się tag twierdzący.",
            "examples": [
                {
                    "en": "You don't like coffee, do you?",
                    "ua": "Nie lubisz kawy, prawda?"
                },
                {
                    "en": "She doesn't work here, does she?",
                    "ua": "Ona tu nie pracuje, prawda?"
                },
                {
                    "en": "They don't live in London, do they?",
                    "ua": "Oni nie mieszkają w Londynie, prawda?"
                }
            ]
        },
        {
            "label": "Past Simple",
            "color": "rose",
            "description": "W Past Simple używamy <strong>did</strong>.",
            "examples": [
                {
                    "en": "You saw the film, didn't you?",
                    "ua": "Widziałeś ten film, prawda?"
                },
                {
                    "en": "She called you, didn't she?",
                    "ua": "Ona do ciebie dzwoniła, prawda?"
                },
                {
                    "en": "They didn't come, did they?",
                    "ua": "Nie przyszli, prawda?"
                }
            ],
            "note": "📌 W tagu zawsze powtarzamy właściwy czasownik pomocniczy, a nie pełny czasownik główny."
        }
    ]
}

{
    "title": "4. Question tags z czasownikami modalnymi",
    "sections": [
        {
            "label": "CAN / COULD / WILL / WOULD",
            "color": "emerald",
            "description": "Przy czasownikach modalnych powtarzamy modal w tagu.",
            "examples": [
                {
                    "en": "You can swim, can't you?",
                    "ua": "Umiesz pływać, prawda?"
                },
                {
                    "en": "She will come, won't she?",
                    "ua": "Ona przyjdzie, prawda?"
                },
                {
                    "en": "They could help, couldn't they?",
                    "ua": "Mogliby pomóc, prawda?"
                },
                {
                    "en": "He would like it, wouldn't he?",
                    "ua": "Spodobałoby mu się to, prawda?"
                }
            ]
        },
        {
            "label": "SHOULD / MUST / MIGHT",
            "color": "sky",
            "description": "Tak samo działają inne modale.",
            "examples": [
                {
                    "en": "We should go, shouldn't we?",
                    "ua": "Powinniśmy iść, prawda?"
                },
                {
                    "en": "You must be tired, mustn't you?",
                    "ua": "Musisz być zmęczony, prawda?"
                },
                {
                    "en": "They might come, mightn't they?",
                    "ua": "Mogą przyjść, prawda?"
                }
            ]
        },
        {
            "label": "Formy przeczące",
            "color": "purple",
            "description": "Jeśli zdanie główne jest przeczące, tag staje się twierdzący.",
            "examples": [
                {
                    "en": "You can't swim, can you?",
                    "ua": "Nie umiesz pływać, prawda?"
                },
                {
                    "en": "She won't come, will she?",
                    "ua": "Ona nie przyjdzie, prawda?"
                },
                {
                    "en": "They shouldn't worry, should they?",
                    "ua": "Nie powinni się martwić, prawda?"
                }
            ],
            "note": "📌 W tagu powtarzamy ten sam modal, ale z przeciwną biegunowością."
        }
    ]
}

{
    "title": "5. Question tags z HAVE/HAS",
    "sections": [
        {
            "label": "Present Perfect",
            "color": "amber",
            "description": "W Present Perfect używamy w tagu <strong>have</strong> albo <strong>has</strong>.",
            "examples": [
                {
                    "en": "You've seen the film, haven't you?",
                    "ua": "Widziałeś ten film, prawda?"
                },
                {
                    "en": "She has finished, hasn't she?",
                    "ua": "Ona skończyła, prawda?"
                },
                {
                    "en": "They haven't arrived, have they?",
                    "ua": "Oni jeszcze nie przyjechali, prawda?"
                }
            ]
        },
        {
            "label": "HAVE GOT",
            "color": "blue",
            "description": "W konstrukcji <strong>have got</strong> też używamy <strong>have/has</strong> w tagu.",
            "examples": [
                {
                    "en": "You've got a car, haven't you?",
                    "ua": "Masz samochód, prawda?"
                },
                {
                    "en": "She has got a dog, hasn't she?",
                    "ua": "Ona ma psa, prawda?"
                },
                {
                    "en": "They haven't got time, have they?",
                    "ua": "Oni nie mają czasu, prawda?"
                }
            ]
        },
        {
            "label": "Wersja amerykańska",
            "color": "rose",
            "description": "W amerykańskim angielskim z czasownikiem <strong>have</strong> często pojawia się <strong>do/does</strong>.",
            "examples": [
                {
                    "en": "You have a car, don't you?",
                    "ua": "Masz samochód, prawda?"
                },
                {
                    "en": "She has a dog, doesn't she?",
                    "ua": "Ona ma psa, prawda?"
                }
            ],
            "note": "📌 Brytyjskie <strong>have got</strong> i amerykańskie <strong>have</strong> tworzą różne tagi."
        }
    ]
}

{
    "title": "6. Question tags z innymi czasami",
    "sections": [
        {
            "label": "Present Continuous",
            "color": "emerald",
            "description": "W Present Continuous używamy <strong>am/is/are</strong>.",
            "examples": [
                {
                    "en": "You're working now, aren't you?",
                    "ua": "Teraz pracujesz, prawda?"
                },
                {
                    "en": "She is coming, isn't she?",
                    "ua": "Ona przychodzi, prawda?"
                },
                {
                    "en": "They aren't playing, are they?",
                    "ua": "Oni nie grają, prawda?"
                }
            ]
        },
        {
            "label": "Past Continuous",
            "color": "sky",
            "description": "W Past Continuous tag tworzymy za pomocą <strong>was</strong> albo <strong>were</strong>.",
            "examples": [
                {
                    "en": "You were sleeping, weren't you?",
                    "ua": "Spałeś, prawda?"
                },
                {
                    "en": "She was studying, wasn't she?",
                    "ua": "Ona się uczyła, prawda?"
                },
                {
                    "en": "They weren't watching TV, were they?",
                    "ua": "Oni nie oglądali telewizji, prawda?"
                }
            ]
        },
        {
            "label": "Future Simple",
            "color": "purple",
            "description": "W Future Simple używamy <strong>will</strong> / <strong>won't</strong>.",
            "examples": [
                {
                    "en": "You will help me, won't you?",
                    "ua": "Pomożesz mi, prawda?"
                },
                {
                    "en": "She will come tomorrow, won't she?",
                    "ua": "Ona przyjdzie jutro, prawda?"
                },
                {
                    "en": "They won't be late, will they?",
                    "ua": "Oni się nie spóźnią, prawda?"
                }
            ],
            "note": "📌 Tag zawsze bierze swój czasownik pomocniczy z głównego zdania."
        }
    ]
}

{
    "title": "7. Wyjątki i szczególne przypadki",
    "sections": [
        {
            "label": "I am → aren't I?",
            "color": "rose",
            "description": "Po <strong>I am</strong> standardowo używamy tagu <strong>aren't I?</strong>",
            "examples": [
                {
                    "en": "I'm right, aren't I?",
                    "ua": "Mam rację, prawda?"
                },
                {
                    "en": "I'm late again, aren't I?",
                    "ua": "Znów się spóźniłem, prawda?"
                },
                {
                    "en": "I am invited, aren't I?",
                    "ua": "Jestem zaproszony, prawda?"
                }
            ]
        },
        {
            "label": "Imperatives",
            "color": "amber",
            "description": "Po trybie rozkazującym często używamy <strong>will you?</strong>",
            "examples": [
                {
                    "en": "Close the door, will you?",
                    "ua": "Zamknij drzwi, dobrze?"
                },
                {
                    "en": "Help me, will you?",
                    "ua": "Pomóż mi, dobrze?"
                },
                {
                    "en": "Don't be late, will you?",
                    "ua": "Nie spóźnij się, dobrze?"
                }
            ]
        },
        {
            "label": "Let's → shall we?",
            "color": "blue",
            "description": "Po <strong>let's</strong> standardowy tag to <strong>shall we?</strong>",
            "examples": [
                {
                    "en": "Let's go to the cinema, shall we?",
                    "ua": "Chodźmy do kina, dobrze?"
                },
                {
                    "en": "Let's take a break, shall we?",
                    "ua": "Zróbmy sobie przerwę, dobrze?"
                }
            ]
        },
        {
            "label": "This / that / these / those",
            "color": "emerald",
            "description": "W tagu zaimki wskazujące zwykle zamieniamy na <strong>it</strong> albo <strong>they</strong>.",
            "examples": [
                {
                    "en": "This is your book, isn't it?",
                    "ua": "To twoja książka, prawda?"
                },
                {
                    "en": "Those were interesting, weren't they?",
                    "ua": "Tamte były interesujące, prawda?"
                }
            ],
            "note": "📌 W tagu zwykle nie powtarzamy <em>this</em> czy <em>those</em>, tylko używamy <em>it</em> albo <em>they</em>."
        }
    ]
}

{
    "title": "8. Intonacja i użycie",
    "sections": [
        {
            "label": "Intonacja opadająca ↘",
            "color": "emerald",
            "description": "Brzmi jak prośba o potwierdzenie czegoś, czego mówiący jest prawie pewien.",
            "examples": [
                {
                    "en": "It's a nice day, isn't it? ↘",
                    "ua": "Ładny dzień, prawda?"
                },
                {
                    "en": "You like coffee, don't you? ↘",
                    "ua": "Lubisz kawę, prawda?"
                }
            ]
        },
        {
            "label": "Intonacja wznosząca ↗",
            "color": "sky",
            "description": "Brzmi bardziej jak prawdziwe pytanie, gdy mówiący nie jest pewien odpowiedzi.",
            "examples": [
                {
                    "en": "You live in London, don't you? ↗",
                    "ua": "Mieszkasz w Londynie, prawda?"
                },
                {
                    "en": "She is coming, isn't she? ↗",
                    "ua": "Ona przychodzi, prawda?"
                }
            ]
        },
        {
            "label": "Do czego służą question tags",
            "color": "purple",
            "description": "Question tags pomagają nie tylko potwierdzać informację, ale też utrzymywać kontakt w rozmowie.",
            "examples": [
                {
                    "en": "confirming information",
                    "ua": "potwierdzanie informacji"
                },
                {
                    "en": "keeping the conversation going",
                    "ua": "podtrzymywanie rozmowy"
                },
                {
                    "en": "being polite",
                    "ua": "uprzejme brzmienie wypowiedzi"
                },
                {
                    "en": "showing interest",
                    "ua": "okazywanie zainteresowania"
                }
            ],
            "note": "📌 Ta sama forma może brzmieć inaczej w zależności od intonacji."
        }
    ]
}

{
    "title": "9. Szybka tabela",
    "intro": "Najważniejsze zasady tworzenia question tags:",
    "rows": [
        {
            "en": "TO BE (am/is/are/was/were)",
            "ua": "Czasownik to be",
            "note": "She is happy, isn't she? / They weren't ready, were they?"
        },
        {
            "en": "DO/DOES/DID",
            "ua": "Czasy proste",
            "note": "You like it, don't you? / She didn't call, did she?"
        },
        {
            "en": "MODALS",
            "ua": "Czasowniki modalne",
            "note": "He can swim, can't he? / They won't come, will they?"
        },
        {
            "en": "HAVE / HAS",
            "ua": "Perfect i have got",
            "note": "You've seen it, haven't you? / She's got a dog, hasn't she?"
        },
        {
            "en": "SPECIAL CASES",
            "ua": "Wyjątki",
            "note": "I'm right, aren't I? / Let's go, shall we?"
        },
        {
            "en": "IMPERATIVES",
            "ua": "Tryb rozkazujący",
            "note": "Close the door, will you?"
        }
    ],
    "warning": "📌 Pamiętaj o podstawowej zasadzie: <strong>twierdzenie + tag przeczący / przeczenie + tag twierdzący</strong>."
}

{
    "title": "10. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Ta sama biegunowość w zdaniu i tagu.",
            "wrong": "❌ She is happy, is she?",
            "right": "✅ <span class=\"font-mono\">She is happy, isn't she?</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Niepoprawny tag po <strong>I am</strong>.",
            "wrong": "❌ I'm right, amn't I?",
            "right": "✅ <span class=\"font-mono\">I'm right, aren't I?</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Użycie <strong>do/does</strong> zamiast modalu w tagu.",
            "wrong": "❌ She can swim, doesn't she?",
            "right": "✅ <span class=\"font-mono\">She can swim, can't she?</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Powtórzenie pełnego rzeczownika zamiast zaimka.",
            "wrong": "❌ John is happy, isn't John?",
            "right": "✅ <span class=\"font-mono\">John is happy, isn't he?</span>"
        }
    ]
}

{
    "title": "12. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwy tag",
    "select_intro": "Wybierz poprawny question tag do zdania.",
    "selects": [
        {
            "label": "She is happy, _____? (isn't she / is she / doesn't she)",
            "prompt": "Który tag jest poprawny?"
        },
        {
            "label": "You like coffee, _____? (don't you / do you / aren't you)",
            "prompt": "Który tag jest poprawny?"
        },
        {
            "label": "They can swim, _____? (can't they / can they / don't they)",
            "prompt": "Który tag jest poprawny?"
        },
        {
            "label": "I'm right, _____? (aren't I / amn't I / am I)",
            "prompt": "Który tag jest poprawny?"
        }
    ],
    "options": [
        "a",
        "b",
        "c"
    ],
    "input_title": "Ćwiczenie 2. Dodaj question tag",
    "input_intro": "Uzupełnij zdanie poprawnym tagiem.",
    "inputs": [
        {
            "before": "She is tired, ",
            "after": "?"
        },
        {
            "before": "You don't like tea, ",
            "after": "?"
        },
        {
            "before": "They will come, ",
            "after": "?"
        },
        {
            "before": "Let's go, ",
            "after": "?"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd w question tag.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "She is happy, is she?",
            "example_target": "She is happy, isn't she?"
        },
        {
            "original": "1. He can drive, doesn't he?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. They aren't ready, aren't they?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "3. I'm late, amn't I?",
            "placeholder": "Popraw błąd"
        }
    ]
}

{
    "title": "Inne lekcje w tej sekcji",
    "items": [
        {
            "label": "Formy pytań",
            "current": false
        },
        {
            "label": "Pytania typu yes / no",
            "current": false
        },
        {
            "label": "Pytania szczegółowe (wh-)",
            "current": false
        },
        {
            "label": "Odpowiedzi na pytania",
            "current": false
        },
        {
            "label": "Pytania alternatywne",
            "current": false
        },
        {
            "label": "Pytania rozłączne (question tags)",
            "current": true
        },
        {
            "label": "Pytania przeczące",
            "current": false
        }
    ]
}
